  1→import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
  2→import { ContentEditable } from "@lexical/react/LexicalContentEditable";
  3→import ImageNode from "../Editor/nodes/ImageNode";
  4→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  5→import { LexicalComposer } from "@lexical/react/LexicalComposer";
  6→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  7→import { useLocation, useNavigate, useParams } from "react-router-dom";
  8→import './contentviewer.css'
  9→import { useEffect, useMemo, useRef, useState } from "react";
 10→import { AnimatePresence, motion } from "framer-motion";
 11→import { MoonLoader } from "react-spinners";
 12→import CalculateText from "../postCards/calculateReadingTime";
 13→import ParseContent from "../postCards/parseData";
 14→import { useBookMarkMutation, useFollowMutation, useLikeMutation, useAddViewsMutation, useReactionMutation } from "../../../utils/useMutation";
 15→import ReactionButton from "../../Reactions/ReactionButton";
 16→import ReactionSummary from "../../Reactions/ReactionSummary";
 17→import { useAuth } from "../../../Context/useAuth";
 18→import CommentSection from "../../comments/comments";
 19→import CanvasViewer from "../Canvas/CanvasViewer";
 20→import debounce from "../../../../helpers/debounce";
 21→import formatCounts from "../../../../helpers/fomatCounts";
 22→import { handleClickProfile, handleCLickContent } from "../../../../helpers/handleClicks";
 23→import { getFollowsData, getJournalById } from "../../../../API/Api";
 24→import { useQuery } from "@tanstack/react-query";
 25→import VerifiedBadge from "../../Badge/VerifiedBadge";
 26→import { getCanvasWholeText, parseCanvasDoc } from "../../../utils/canvasDoc";
 27→import RepostModal from "../../RepostModal/RepostModal";
 28→import ShareMenu from "../../ShareMenu/ShareMenu";
 29→import getShareUrl from "../../../utils/getShareUrl";
 30→import usePostSeo from "../../../seo/usePostSeo";
 31→import RelatedPosts from "../../Discovery/RelatedPosts";
 32→
 33→const normalizeInteractionFlag = (value) => {
 34→    if(typeof value === 'boolean') return value;
 35→    if(typeof value === 'string'){
 36→        const normalized = value.trim().toLowerCase();
 37→        if(normalized === 'true') return true;
 38→        if(normalized === 'false') return false;
 39→    }
 40→    if(typeof value === 'number'){
 41→        return value === 1;
 42→    }
 43→    return Boolean(value);
 44→};
 45→
 46→const normalizeCount = (value) => {
 47→    const number = Number(value);
 48→    if(!Number.isFinite(number) || number < 0){
 49→        return 0;
 50→    }
 51→    return number;
 52→};
 53→
 54→const getNextToggleCount = (isActive, currentCount) => {
 55→    return isActive
 56→        ? Math.max(0, currentCount - 1)
 57→        : currentCount + 1;
 58→};
 59→
 60→const ContentView = () => {
 61→    const navigate = useNavigate();
 62→    const [showBackButton, setShowBackButton] = useState(true);
 63→    const { session, user, openAuthModal } = useAuth();
 64→
 65→    const timeOutRef = useRef();
 66→    const timeOutRefBookmark = useRef();
 67→    const likeInFlightRef = useRef(false);
 68→    const bookmarkInFlightRef = useRef(false);
 69→
 70→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 71→    const [isLiked, setIsliked] = useState(false);
 72→    const [likesCount, setLikesCount] = useState(0);
 73→    const [userReaction, setUserReaction] = useState(null);
 74→    const [reactionCount, setReactionCount] = useState(0);
 75→    const [isBookmarked, setIsBookmarked] = useState(false);
 76→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 77→
 78→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 79→    const [showRepostModal, setShowRepostModal] = useState(false);
 80→    const [showShareMenu, setShowShareMenu] = useState(false);
 81→
 82→    const contentRef = useRef();
 83→
 84→    const theme = {
 85→        paragraph: 'editor-paragraph',
 86→        heading: {
 87→            h1: 'editor-heading-h1',
 88→            h2: 'editor-heading-h2',
 89→            h3: 'editor-heading-h3',
 90→        },
 91→        quote: 'editor-quote',
 92→        text: {
 93→            bold: 'editor-text-bold',
 94→            italic: 'editor-text-italic',
 95→            underline: 'editor-text-underline',
 96→        }
 97→    }
 98→
 99→    const location = useLocation();
100→    const { journalId } = useParams();
101→    const statePostData = location.state;
102→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
103→
104→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
105→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
106→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
107→        enabled: shouldFetchPost,
108→        staleTime: 1000 * 60 * 5,
109→        refetchOnWindowFocus: false,
110→    });
111→
112→    const postData = useMemo(() => {
113→        const journal = fetchedJournalData?.journal;
114→        if(journal){
115→            const postType = journal?.post_type || 'text';
116→            const parsedContent = ParseContent(journal?.content);
117→            const canvasDoc = postType === 'canvas' ? parseCanvasDoc(journal?.canvas_doc) : null;
118→            const wholeText = postType === 'canvas'
119→                ? getCanvasWholeText(canvasDoc)
120→                : (parsedContent?.wholeText || '');
121→
122→            return {
123→                postType: postType,
124→                content: journal?.content,
125→                canvasDoc: canvasDoc,
126→                wholeText: wholeText,
127→                title: journal?.title,
128→                userId: journal?.users?.id || journal?.user_id,
129→                name: journal?.users?.name,
130→                avatar: journal?.users?.image_url,
131→                created_at: journal?.created_at,
132→                journalId: journal?.id,
133→                isLiked: journal?.has_liked,
134→                commentsCount: journal?.comment_count?.[0]?.count || 0,
135→                isBookmarked: journal?.has_bookmarked,
136→                likesCount: journal?.like_count?.[0]?.count || 0,
137→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
138→                badge: journal?.users?.badge,
139→                isRepost: journal?.is_repost === true,
140→                repostCaption: journal?.repost_caption || '',
141→                repostSource: journal?.repost_source || null,
142→                userReaction: journal?.user_reaction || null,
143→                reactionCount: journal?.reaction_count?.[0]?.count || 0
144→            };
145→        }
146→
147→        if(!statePostData){
148→            return null;
149→        }
150→
151→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
152→        const parsedContent = ParseContent(statePostData?.content);
153→        const canvasDoc = inferredPostType === 'canvas' ? parseCanvasDoc(statePostData?.canvasDoc) : null;
154→
155→        return {
156→            postType: inferredPostType,
157→            content: statePostData?.content,
158→            canvasDoc: canvasDoc,
159→            wholeText: inferredPostType === 'canvas'
160→                ? (statePostData?.wholeText || getCanvasWholeText(canvasDoc))
161→                : (statePostData?.wholeText || parsedContent?.wholeText || ''),
162→            title: statePostData?.title,
163→            userId: statePostData?.userId,
164→            name: statePostData?.name,
165→            avatar: statePostData?.avatar,
166→            created_at: statePostData?.created_at,
167→            journalId: statePostData?.journalId,
168→            isLiked: statePostData?.isLiked,
169→            commentsCount: statePostData?.commentsCount || 0,
170→            isBookmarked: statePostData?.isBookmarked,
171→            likesCount: statePostData?.likesCount || 0,
172→            bookmarksCount: statePostData?.bookmarksCount || 0,
173→            badge: statePostData?.badge,
174→            isRepost: statePostData?.isRepost === true,
175→            repostCaption: statePostData?.repostCaption || '',
176→            repostSource: statePostData?.repostSource || null,
177→            userReaction: statePostData?.userReaction || null,
178→            reactionCount: statePostData?.reactionCount || 0
179→        };
180→    }, [fetchedJournalData, statePostData]);
181→
182→    usePostSeo(postData);
183→
184→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
185→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
186→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
187→        staleTime: 1000 * 60 * 60,
188→        cacheTime: 1000 * 60 * 60,
189→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
190→    });
191→
192→    const handleclickUserProfile = handleClickProfile(navigate);
193→    const viewContent = handleCLickContent(navigate);
194→
195→    const mutateViews = useAddViewsMutation(session);
196→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
197→    const mutationReaction = useReactionMutation(session, user?.userData?.[0]?.id);
198→
199→    const handleReaction = (e, journalId, receiverId, reactionType) => {
200→        e.stopPropagation();
201→        if (!session) { openAuthModal?.(); return; }
202→
203→        const wasReacted = userReaction;
204→        if (wasReacted === reactionType) {
205→            setUserReaction(null);
206→            setReactionCount((c) => Math.max(c - 1, 0));
207→        } else if (wasReacted) {
208→            setUserReaction(reactionType);
209→        } else {
210→            setUserReaction(reactionType);
211→            setReactionCount((c) => c + 1);
212→        }
213→        mutationReaction.mutate({ journalId, receiverId, reactionType });
214→    };
215→
216→    const handleClickLike = async (e, journalId, receiverId, senderImageUrl, sendername, senderEmail) => {
217→        e.stopPropagation();
218→        if(likeInFlightRef.current){
219→            return;
220→        }
221→        if(!session){
222→            openAuthModal?.();
223→            return;
224→        }
225→        const wasLiked = normalizeInteractionFlag(isLiked);
226→        likeInFlightRef.current = true;
227→        setIsliked(!wasLiked);
228→        setLikesCount((prevCount) => getNextToggleCount(wasLiked, normalizeCount(prevCount)));
229→        mutationLike.mutate(
230→            { journalId, receiverId, senderImageUrl, sendername, senderEmail },
231→            {
232→                onSettled: () => {
233→                    likeInFlightRef.current = false;
234→                }
235→            }
236→        );
237→    }
238→
239→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
240→    const handleClickBookmark = async (e, journalId) => {
241→        e.stopPropagation();
242→        if(bookmarkInFlightRef.current){
243→            return;
244→        }
245→        if(!session){
246→            openAuthModal?.();
247→            return;
248→        }
249→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
250→        bookmarkInFlightRef.current = true;
251→        setIsBookmarked(!wasBookmarked);
252→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
253→        let response = null;
254→        try {
255→            response = await mutationBookmark.mutateAsync({ journalId });
256→        } finally {
257→            bookmarkInFlightRef.current = false;
258→        }
259→        
260→        if(timeOutRefBookmark.current){
261→            clearTimeout(timeOutRefBookmark.current);
262→        }
263→        if (response?.message === 'success') {
264→            setBookmarkedMessage('Post was added to your Bookmarks'); 
265→        } else if(response?.message === 'deleted'){
266→            setBookmarkedMessage('Post was removed from your Bookmarks');
267→        }
268→            
269→        timeOutRefBookmark.current = setTimeout(() => {
270→            setBookmarkedMessage('');
271→        }, 1500);
272→
273→    }
274→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
275→
276→    const mutationFollow = useFollowMutation(session);
277→    const handleClickFollow = async (e, followingId, followerId) => {
278→        e.stopPropagation();
279→        if(!session) return openAuthModal();
280→        mutationFollow.mutate({ followingId, followerId });
281→    }
282→    const debounceClickFollow = debounce(handleClickFollow, 100);
283→
284→    const handleBackLocation = (e) => {
285→        e.stopPropagation();
286→        window.history.back();
287→    }
288→
289→    const hanldeClickComments = (e) => {
290→        e.stopPropagation();
291→        if(!session) return openAuthModal();
292→        setShowCommentsContainer(true);
293→    }
294→
295→    const handleRemixCanvas = (e) => {
296→        e.stopPropagation();
297→        if(!session){
298→            return;
299→        }
300→
301→        const sourceTitle = typeof postData?.title === 'string' ? postData.title.trim() : '';
302→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
303→            ? sourceTitle
304→            : `Remix: ${sourceTitle || 'Canvas'}`;
305→
306→        navigate('/home', {
307→            state: {
308→                openEditor: true,
309→                editorMode: 'canvas',
310→                initialTitle: remixTitle,
311→                initialCanvasDoc: postData?.canvasDoc || null,
312→                remixSource: {
313→                    journalId: postData?.journalId,
314→                    authorName: postData?.name || 'Unknown'
315→                }
316→            }
317→        });
318→    }
319→
320→    const handleCLoseComments = () => {
321→        setShowCommentsContainer(false);
322→    }
323→
324→    useEffect(() => {
325→        if (!postData) return;
326→        setLikesCount(normalizeCount(postData?.likesCount));
327→        setBookmarkCounts(normalizeCount(postData?.bookmarksCount));
328→        setIsliked(normalizeInteractionFlag(postData?.isLiked));
329→        setIsBookmarked(normalizeInteractionFlag(postData?.isBookmarked));
330→        setUserReaction(postData?.userReaction || null);
331→        setReactionCount(normalizeCount(postData?.reactionCount));
332→    }, [postData?.likesCount, postData?.bookmarksCount, postData?.isLiked, postData?.isBookmarked, postData?.userReaction, postData?.reactionCount]);
333→
334→    useEffect(() => {
335→        const hideBackBttn = () => {
336→            setShowBackButton(false);
337→            if (timeOutRef.current) {
338→                clearTimeout(timeOutRef.current);
339→            }
340→            timeOutRef.current = setTimeout(() => {
341→                setShowBackButton(true);
342→            }, 300);
343→        }
344→
345→        document.addEventListener('scroll', hideBackBttn, true);
346→        return () => {
347→            if (timeOutRef.current) {
348→                clearTimeout(timeOutRef.current);
349→            }
350→            document.removeEventListener('scroll', hideBackBttn, true);
351→        }
352→    }, []);
353→
354→    if (isLoadingJournalById || isLoadingFollows) {
355→        return (
356→            <div className="cv-loading">
357→                <MoonLoader loading={isLoadingJournalById || isLoadingFollows} color="var(--loader-color)" size={25} />
358→            </div>
359→        )
360→    }
361→
362→    if (!postData) {
363→        return (
364→            <div className="cv-loading">
365→                <p>Post is unavailable.</p>
366→                <button onClick={handleBackLocation} className="cv-back-btn" style={{ marginTop: "12px" }}>
367→                    Go back
368→                </button>
369→            </div>
370→        )
371→    }
372→
373→    return (
374→        <>
375→            {showCommentsContainer && (
376→                <AnimatePresence>
377→                    <CommentSection onclose={handleCLoseComments} postId={postData?.journalId} receiverId={postData?.userId} />
378→                </AnimatePresence>
379→            )}
380→
381→            <div ref={contentRef} className="cv-container">
382→                {/* Back header */}
383→                <AnimatePresence>
384→                    {showBackButton && (
385→                        <motion.div
386→                            className="cv-header"
387→                            initial={{ opacity: 0 }}
388→                            animate={{ opacity: 1, transition: { duration: 0.15 } }}
389→                            exit={{ opacity: 0, transition: { duration: 0.15 } }}
390→                        >
391→                            <button onClick={handleBackLocation} className="cv-back-btn">
392→                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 -960 960 960">
393→                                    <path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z" />
394→                                </svg>
395→                            </button>
396→                            <p className="cv-header-label">Post</p>
397→                        </motion.div>
398→                    )}
399→                </AnimatePresence>
400→
401→                <article className="cv-article">
402→                    {postData?.isRepost ? (
403→                        <>
404→                            {/* ── Repost view: quote on top, original post nested below ── */}
405→
406→                            {/* Reposter quote section */}
407→                            <div className="cv-repost-quote-section">
408→                                <div className="cv-repost-badge">
409→                                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="var(--text-faint)">
410→                                        <path d="M7 7h10l-1.293-1.293a1 1 0 0 1 1.414-1.414l3 3a1 1 0 0 1 0 1.414l-3 3a1 1 0 0 1-1.414-1.414L17 9H7a1 1 0 0 1-1-1V5a1 1 0 0 1 2 0v2zm10 10H7l1.293 1.293a1 1 0 0 1-1.414 1.414l-3-3a1 1 0 0 1 0-1.414l3-3a1 1 0 1 1 1.414 1.414L7 15h10a1 1 0 0 1 1 1v3a1 1 0 0 1-2 0v-2z"/>
411→                                    </svg>
412→                                    <span
413→                                        onClick={(e) => handleclickUserProfile(e, user?.userData?.[0]?.id, postData?.userId)}
414→                                        className="cv-repost-badge-name"
415→                                    >
416→                                        {postData?.name}
417→                                    </span>
418→                                    <VerifiedBadge badge={postData?.badge} size={14} />
419→                                    <span className="cv-repost-badge-label">reposted</span>
420→                                    <span className="cv-repost-badge-date">
421→                                        {new Date(postData?.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
422→                                    </span>
423→                                </div>
424→
425→                                {postData.repostCaption && (
426→                                    <p className="cv-repost-caption">{postData.repostCaption}</p>
427→                                )}
428→                            </div>
429→
430→                            {/* Original post nested below */}
431→                            {postData.repostSource ? (
432→                                <div
433→                                    className="cv-repost-embedded"
434→                                    onClick={(e) => {
435→                                        e.stopPropagation();
436→                                        if(session){
437→                                            const formadata = new FormData();
438→                                            formadata.append('journalId', postData.repostSource.id);
439→                                            mutateViews.mutate(formadata);
440→                                        }
441→                                        const src = postData.repostSource;
442→                                        const srcParsed = ParseContent(src.content);
443→                                        viewContent(
444→                                            e,
445→                                            src.content,
446→                                            srcParsed?.wholeText || '',
447→                                            src.title,
448→                                            src.users?.id,
449→                                            src.users?.name,
450→                                            src.users?.image_url,
451→                                            src.created_at,
452→                                            src.id,
453→                                            false, 0, false, 0, 0,
454→                                            src.users?.badge
455→                                        );
456→                                    }}
457→                                >
458→                                    <div className="cv-repost-embedded-meta">
459→                                        <img className="cv-repost-embedded-avatar" src={postData.repostSource.users?.image_url || '/assets/profile.jpg'} alt="original author" />
460→                                        <span className="cv-repost-embedded-name">{postData.repostSource.users?.name}</span>
461→                                        <VerifiedBadge badge={postData.repostSource.users?.badge} size={14} />
462→                                        <span className="cv-repost-embedded-date">
463→                                            {new Date(postData.repostSource.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
464→                                        </span>
465→                                    </div>
466→                                    <h2 className="cv-repost-embedded-title">{postData.repostSource.title}</h2>
467→                                    <div className="cv-repost-embedded-content">
468→                                        {postData.repostSource.post_type === 'canvas' ? (
469→                                            <CanvasViewer canvasDoc={parseCanvasDoc(postData.repostSource.canvas_doc)} />
470→                                        ) : postData.repostSource.content ? (
471→                                            <LexicalComposer initialConfig={{
472→                                                namespace: "RepostSourceViewer",
473→                                                theme: theme,
474→                                                editable: false,
475→                                                editorState: postData.repostSource.content,
476→                                                nodes: [HeadingNode, ImageNode, QuoteNode],
477→                                                onError(error) { throw error; },
478→                                            }}>
479→                                                <RichTextPlugin
480→                                                    contentEditable={<ContentEditable />}
481→                                                    ErrorBoundary={LexicalErrorBoundary}
482→                                                />
483→                                            </LexicalComposer>
484→                                        ) : null}
485→                                    </div>
486→                                </div>
487→                            ) : (
488→                                <div className="cv-repost-unavailable">
489→                                    This post is no longer available
490→                                </div>
491→                            )}
492→
493→                            {/* Reaction summary */}
494→                            <ReactionSummary journalId={postData?.journalId} />
495→
496→                            {/* Action bar */}
497→                            <div className="cv-actions">
498→                                <div className="cv-action-btn">
499→                                    <ReactionButton
500→                                        userReaction={userReaction}
501→                                        reactionCount={reactionCount || likesCount}
502→                                        onReact={(reactionType) => handleReaction({ stopPropagation: () => {} }, postData?.journalId, postData?.userId, reactionType)}
503→                                        disabled={!session}
504→                                    />
505→                                </div>
506→
507→                                <button className="cv-action-btn" onClick={hanldeClickComments}>
508→                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="var(--icon-default)">
509→                                        <path fillRule="evenodd" clipRule="evenodd" d="M11.9862 0.763672C6.07454 0.763672 1.23621 5.36133 1.23621 11.1034C1.23621 13.5057 2.10188 15.7237 3.55066 17.4735C5.46882 19.8566 8.48271 21.3843 11.8522 21.4238L11.8878 21.4367C11.9902 21.4735 12.1385 21.5265 12.3236 21.5916C12.6936 21.7216 13.2115 21.9001 13.8035 22.0941C14.9799 22.4797 16.4767 22.9358 17.6892 23.1894C18.303 23.3178 18.9306 23.1718 19.4096 22.8608C19.8872 22.5507 20.3019 22.0126 20.3019 21.3173C20.3019 20.9046 20.1354 20.4987 19.9732 20.1857C19.8007 19.8529 19.5794 19.5251 19.371 19.2448C19.2691 19.1076 19.1676 18.9782 19.0724 18.8609C21.3193 16.9815 22.7362 14.2061 22.7362 11.1034C22.7362 7.55126 20.8865 4.4319 18.073 2.58609C16.3321 1.4227 14.2426 0.763672 11.9862 0.763672ZM18.3637 6.03728C18.1546 5.67972 17.6953 5.55937 17.3377 5.76847C16.9801 5.97757 16.8598 6.43694 17.0689 6.7945C17.8131 8.0671 18.2362 9.53599 18.2362 11.1034C18.2362 12.6662 17.8138 14.1316 17.0693 15.4016C16.8598 15.7589 16.9797 16.2184 17.337 16.4279C17.6943 16.6374 18.1538 16.5175 18.3633 16.1602C19.2385 14.6673 19.7362 12.941 19.7362 11.1034C19.7362 9.26158 19.238 7.53236 18.3637 6.03728Z" fill="var(--icon-default)" />
510→                                    </svg>
511→                                    <span>{formatCounts(postData?.commentsCount)}</span>
512→                                </button>
513→
514→                                <button className="cv-action-btn" onClick={(e) => debounceClickBookmark(e, postData?.journalId)}>
515→                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none">
