  1→import { useState } from "react";
  2→import { motion, AnimatePresence } from "framer-motion";
  3→import { useRepostMutation } from "../../utils/useMutation";
  4→import { useAuth } from "../../Context/useAuth";
  5→import VerifiedBadge from "../Badge/VerifiedBadge";
  6→import './repostmodal.css';
  7→
  8→const CAPTION_MAX = 280;
  9→
 10→const RepostModal = ({ journal, onClose }) => {
 11→    const { session } = useAuth();
 12→    const [caption, setCaption] = useState('');
 13→    const [error, setError] = useState('');
 14→
 15→    const repostMutation = useRepostMutation(session);
 16→
 17→    const handleSubmit = () => {
 18→        if(repostMutation.isPending) return;
 19→        setError('');
 20→
 21→        repostMutation.mutate(
 22→            {
 23→                sourceJournalId: journal.id,
 24→                caption: caption.trim() || ''
 25→            },
 26→            {
 27→                onSuccess: () => {
 28→                    onClose('success');
 29→                },
 30→                onError: (err) => {
 31→                    setError(err?.message || 'Failed to repost');
 32→                }
 33→            }
 34→        );
 35→    };
 36→
 37→    return (
 38→        <AnimatePresence>
 39→            <motion.div
 40→                className="repost-overlay"
 41→                initial={{ opacity: 0 }}
 42→                animate={{ opacity: 1 }}
 43→                exit={{ opacity: 0 }}
 44→                transition={{ duration: 0.2 }}
 45→                onClick={() => onClose()}
 46→            >
 47→                <motion.div
 48→                    className="repost-modal"
 49→                    initial={{ opacity: 0, scale: 0.92, y: 20 }}
 50→                    animate={{ opacity: 1, scale: 1, y: 0 }}
 51→                    exit={{ opacity: 0, scale: 0.92, y: 20 }}
 52→                    transition={{ type: 'spring', stiffness: 400, damping: 30 }}
 53→                    onClick={(e) => e.stopPropagation()}
 54→                >
 55→                    <div className="repost-modal-header">
 56→                        <h3 className="repost-modal-title">Repost</h3>
 57→                        <button className="repost-modal-close" onClick={() => onClose()}>
 58→                            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
 59→                                <path d="M18.3 5.71a1 1 0 0 0-1.42 0L12 10.59 7.12 5.71a1 1 0 1 0-1.42 1.42L10.59 12l-4.88 4.88a1 1 0 1 0 1.42 1.42L12 13.41l4.88 4.88a1 1 0 0 0 1.42-1.42L13.41 12l4.88-4.88a1 1 0 0 0 0-1.41Z"/>
 60→                            </svg>
 61→                        </button>
 62→                    </div>
 63→
 64→                    <div className="repost-original-preview">
 65→                        <div className="repost-original-author">
 66→                            <img
 67→                                className="repost-original-avatar"
 68→                                src={journal?.users?.image_url || '/assets/profile.jpg'}
 69→                                alt="author"
 70→                            />
 71→                            <span className="repost-original-name">{journal?.users?.name}</span>
 72→                            <VerifiedBadge badge={journal?.users?.badge} size={12} />
 73→                        </div>
 74→                        <p className="repost-original-title">{journal?.title?.length > 80 ? journal.title.substring(0, 80) + '...' : journal?.title}</p>
 75→                    </div>
 76→
 77→                    <div className="repost-caption-container">
 78→                        <textarea
 79→                            className="repost-caption-input"
 80→                            placeholder="Add your thoughts (optional)..."
 81→                            value={caption}
 82→                            onChange={(e) => {
 83→                                if(e.target.value.length <= CAPTION_MAX){
 84→                                    setCaption(e.target.value);
 85→                                }
 86→                            }}
 87→                            maxLength={CAPTION_MAX}
 88→                            rows={3}
 89→                        />
 90→                        <span className={`repost-char-count ${caption.length >= CAPTION_MAX ? 'at-limit' : ''}`}>
 91→                            {caption.length}/{CAPTION_MAX}
 92→                        </span>
 93→                    </div>
 94→
 95→                    {error && (
 96→                        <p className="repost-error">{error}</p>
 97→                    )}
 98→
 99→                    <div className="repost-modal-actions">
100→                        <button className="repost-cancel-btn" onClick={() => onClose()}>Cancel</button>
101→                        <button
102→                            className="repost-submit-btn"
103→                            onClick={handleSubmit}
104→                            disabled={repostMutation.isPending}
105→                        >
106→                            {repostMutation.isPending ? 'Reposting...' : 'Repost'}
107→                        </button>
108→                    </div>
109→                </motion.div>
110→            </motion.div>
111→        </AnimatePresence>
112→    );
113→};
114→
115→export default RepostModal;
